(function(){
  // Block right-click context menu
  document.addEventListener('contextmenu',function(e){e.preventDefault();});
  // Block F12, Ctrl+Shift+I, Ctrl+Shift+C, Ctrl+U, Ctrl+S
  document.addEventListener('keydown',function(e){
    if(e.key==='F12'||(e.ctrlKey&&e.shiftKey&&(e.key==='i'||e.key==='I'||e.key==='c'||e.key==='C'||e.key==='j'||e.key==='J'))||(e.ctrlKey&&(e.key==='u'||e.key==='U'||e.key==='s'||e.key==='S'))){
      e.preventDefault();
      return false;
    }
  });
  // Clear console periodically
  setInterval(function(){try{console.clear();}catch(e){}},1000);
})();
